import {
getFirestore,
collection,
getDocs,
doc,
updateDoc
} from "https://www.gstatic.com/firebasejs/10.12.2/firebase-firestore.js";

const firebaseConfig = {
  apiKey: "AIzaSyAc6MUEav7H7Y-t1H5G3diAXiQHPFpTkrA",
  authDomain: "sarhad-dimension.firebaseapp.com",
  projectId: "sarhad-dimension",
  storageBucket: "sarhad-dimension.firebasestorage.app",
  messagingSenderId: "363344322133",
  appId: "1:363344322133:web:92f5b4f87f2efa13f8bedc",
  measurementId: "G-5FMPK3QWBZ"
};

const app = initializeApp(firebaseConfig);
const db = getFirestore(app);

// APPROVE CASH
window.approve = async function(id) {
    await updateDoc(doc(db,"registrations",id),{
        status: "Paid"
    });
    location.reload();
};

// CERTIFICATE
window.generateCertificate = function(name, event, college){

    const { jsPDF } = window.jspdf;
    const pdf = new jsPDF("landscape");

    const logo = "data:image/png;base64,";

    // logo
    pdf.addImage(logo, "PNG", 20, 15, 30, 30);

    // border
    pdf.setDrawColor(0, 0, 255);
    pdf.setLineWidth(3);
    pdf.rect(10, 10, 277, 190);

    pdf.setFont("times", "bold");
    pdf.setFontSize(30);
    pdf.text("CERTIFICATE OF PARTICIPATION", 140, 40, null, null, "center");

    pdf.setFontSize(18);
    pdf.text("Sarhad College", 140, 55, null, null, "center");

    pdf.setFont("times", "normal");
    pdf.setFontSize(16);
    pdf.text("This is to certify that", 140, 80, null, null, "center");

    pdf.setFont("times", "bold");
    pdf.setFontSize(22);
    pdf.text(name, 140, 100, null, null, "center");

    const safeCollege = college || "Sarhad College Student";

    pdf.setFont("times", "normal");
    pdf.setFontSize(16);
    pdf.text(`from ${safeCollege}`, 140, 115, null, null, "center");

    pdf.text("has successfully participated in", 140, 130, null, null, "center");

    pdf.setFont("times", "bold");
    pdf.setFontSize(18);
    pdf.text(event, 140, 145, null, null, "center");

    pdf.text("Sarhad Dimension 2026", 140, 165, null, null, "center");

    pdf.text("Event Coordinator", 230, 180);

    pdf.save(name + "_certificate.pdf");
};

// LOAD DATA
async function load(){

const snap = await getDocs(collection(db,"registrations"));

snap.forEach(docSnap=>{
const d = docSnap.data();
const id = docSnap.id;

const li = document.createElement("li");

li.innerHTML = `
${d.name} | ${d.phone} | ${d.event} | ${d.status}
<button onclick="approve('${id}')">Approve</button>
<button onclick="generateCertificate('${d.name}','${d.event}','${d.college}')">PDF</button>
`;

if(d.event==="Coding Competition")
squidgameList.appendChild(li);

if(d.event==="Seminar Workshop")
seminarList.appendChild(li);

if(d.event==="AI generates Photography")
photographyList.appendChild(li);

if(d.event==="BGMI")
gamingList.appendChild(li);

if(d.event==="BGMI")
doodleartList.appendChild(li);

if(d.event==="BGMI")
sellerstallList.appendChild(li);

});

}

load();